import { useEffect, useRef } from 'react';

/**
 * Attaches an IntersectionObserver to the returned ref.
 * `callback` fires whenever the element enters the viewport.
 * `threshold` is stable — pass a primitive, not an object literal, to avoid re-runs.
 */
const useIntersectionObserver = (callback, { threshold = 0.1, rootMargin = '0px' } = {}) => {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) callback(); },
      { threshold, rootMargin }
    );

    observer.observe(el);
    return () => observer.disconnect();
  // threshold and rootMargin are primitives — safe in dep array
  }, [callback, threshold, rootMargin]);

  return ref;
};

export default useIntersectionObserver;
